import useScrollSpy from '../../helpers/hooks/useScrollSpy';
import React, { FunctionComponent, useRef } from 'react';
import styled from 'styled-components';
import CommentWidget from './CommentWidget';
import { Link } from 'gatsby';

interface PostContentProps {
  title: string;
  date: string;
  html: string;
  tableOfContents: string;
  pageContext: {
    previous?: {
      frontmatter: {
        title: string;
      };
      fields: {
        slug: string;
      };
    };
    next?: {
      frontmatter: {
        title: string;
      };
      fields: {
        slug: string;
      };
    };
    slug: string;
  };
}

const PostWrapper = styled.div`
  display: flex;
  position: relative;
  padding: 100px 0;
  margin: 0 auto;
  align-items: start;

  @media (max-width: 1024px) {
    margin: 0;
  }
`;
const PostContentWrapper = styled.div`
  width: 80%;
  max-width: 1024px;

  @media (max-width: 1024px) {
    width: 100%;
  }
`;

const PostHeader = styled.header`
  padding: 0 20px;
  margin-bottom: 48px;

  & > h1 {
    margin-bottom: 8px;
    font-size: 40px;
  }
`;

const TocRenderer = styled.aside`
  display: inline-block;
  margin-left: 10px;
  position: sticky;
  top: 0;
  left: 10px;
  transition: all 0.125s esse-in 0s;
  color: rgba(0, 0, 0, 0.4);
  padding: 0 0.75rem;
  border-left: 2px solid gray;

  & ul {
    list-style: none;

    & li {
      margin-top: 5px;

      & a.reach {
        color: #000000;
        transform: scale(1.05);
      }
    }
  }

  @media (max-width: 1024px) {
    display: none;
  }
`;

const MarkdownRenderer = styled.article`
  // Renderer Style
  display: flex;
  flex-direction: column;
  word-break: break-all;
  margin-bottom: 250px;
  padding: 0 20px;
  width: 100%;

  @media (max-width: 1024px) {
    margin-bottom: 48px;
  }

  // Markdown Style
  line-height: 1.8;
  font-size: 16px;
  font-weight: 400;

  // Apply Padding Attribute to All Elements
  p {
    padding: 3px 0;
  }

  // Adjust Heading Element Style
  h1,
  h2,
  h3 {
    font-weight: 800;
  }

  * + h1 {
    margin-top: 60px;
  }

  * + h2 {
    margin-top: 40px;
  }

  * + h3 {
    margin-top: 20px;
  }

  hr + h1,
  hr + h2,
  hr + h3 {
    margin-top: 0;
  }

  h1 {
    font-size: 30px;
  }

  h2 {
    font-size: 25px;
  }

  h3 {
    font-size: 20px;
  }

  // Adjust Quotation Element Style
  blockquote {
    margin: 30px 0;
    padding: 5px 15px;
    border-left: 2px solid #000000;
    font-weight: 800;
  }

  // Adjust List Element Style
  ol,
  ul {
    margin-left: 20px;
    padding: 10px 0;
  }

  // Adjust Horizontal Rule style
  hr {
    border: 1px solid #000000;
    margin: 100px 0;
  }

  // Adjust Link Element Style
  a {
    color: #4263eb;
    text-decoration: underline;
  }

  // Adjust Code Style
  pre[class*='language-'] {
    margin: 30px 0;
    padding: 15px;
    font-size: 15px;

    ::-webkit-scrollbar-thumb {
      background: rgba(255, 255, 255, 0.5);
      border-radius: 3px;
    }
  }

  code[class*='language-'],
  pre[class*='language-'] {
    tab-size: 2;
  }

  img {
    width: 100%;
  }

  summary {
    font-size: 24px;
  }
`;

const PostNavigator = styled.section`
  margin: 40px 0;
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  list-style: none;
  padding: 0 20px;

  & h5 {
    font-size: 24px;
    margin-bottom: 8px;
  }

  & a {
    border-radius: 6px;
    font-size: 20px;
    color: #cc007a;
    font-weight: 700;
  }
`;

const PostContent: FunctionComponent<PostContentProps> = function ({
  title,
  date,
  html,
  tableOfContents,
  pageContext,
}) {
  const tocRef = useRef<HTMLElement>(null);
  const markdownRef = useRef<HTMLElement>(null);
  useScrollSpy(tocRef, markdownRef);

  return (
    <>
      <PostWrapper>
        <PostContentWrapper>
          <PostHeader>
            <h1>{title}</h1>
            <time>{date}</time>
          </PostHeader>
          <MarkdownRenderer
            ref={markdownRef}
            dangerouslySetInnerHTML={{ __html: html }}
          />
          {(pageContext.previous || pageContext.next) && (
            <PostNavigator>
              {pageContext.previous && (
                <Link to={pageContext.previous.fields.slug}>
                  <h5>이전글</h5>
                  <i>{'← '}</i>
                  {pageContext.previous.frontmatter.title}
                </Link>
              )}
              {pageContext.next && (
                <Link to={pageContext.next.fields.slug}>
                  <h5>다음글</h5>
                  {pageContext.next.frontmatter.title}
                  <i>{' →'}</i>
                </Link>
              )}
            </PostNavigator>
          )}
          <CommentWidget />
        </PostContentWrapper>
        <TocRenderer
          ref={tocRef}
          dangerouslySetInnerHTML={{ __html: tableOfContents }}
        />
      </PostWrapper>
    </>
  );
};

export default PostContent;
